section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/security-as-code.json",
  "type": "object",
  "required": [
    "pipeline_stage",
    "scanner_or_policy",
    "block_severity_threshold",
    "policy_repo_path",
    "enforce_mode",
    "waiver_required_for_exception",
    "audit_destination",
    "signing_attestation"
  ],
  "properties": {
    "pipeline_stage": {
      "type": "string",
      "description": "enum (build | test | sca | sast | sign | deploy | admission | runtime)"
    },
    "scanner_or_policy": {
      "type": "string",
      "description": "string (tool name + version)"
    },
    "block_severity_threshold": {
      "type": "string",
      "description": "enum (critical | high | medium | low)"
    },
    "policy_repo_path": {
      "type": "string",
      "description": "string (relative to monorepo)"
    },
    "enforce_mode": {
      "type": "string",
      "description": "enum (enforce | audit)"
    },
    "waiver_required_for_exception": {
      "type": "boolean",
      "description": "boolean (true)"
    },
    "audit_destination": {
      "type": "string",
      "description": "string (SIEM / log store URL)"
    },
    "signing_attestation": {
      "type": "object",
      "description": "object (cosign + key reference)"
    }
  }
}
